content:
{
  "sentences": [
    {
      "text": "除了中文以外，我也會說一點英文。",
      "pinyin": "Chúle zhōngwén yǐwài, wǒ yě huì shuō yīdiǎn yīngwén.",
      "pinyin_numeric": "chu2le zhong1wen2 yi3wai4, wo3 ye3 hui4 shuo1 yi1dian3 ying1wen2.",
      "translation_en": "Besides Chinese, I can also speak a little English.",
      "translation_ko": "중국어 외에도 저는 영어를 조금 할 수 있습니다."
    },
    {
      "text": "除了看電影以外，我們還喜歡聽音樂。",
      "pinyin": "Chúle kàn diànyǐng yǐwài, wǒmen hái xǐhuān tīng yīnyuè.",
      "pinyin_numeric": "chu2le kan4 dian4ying3 yi3wai4, wo3men hai2 xi3huan1 ting1 yin1yue4.",
      "translation_en": "Besides watching movies, we also like listening to music.",
      "translation_ko": "영화 보는 것 외에도 우리는 음악 듣는 것을 좋아합니다."
    },
    {
      "text": "除了牛肉麵以外，這家餐廳的滷肉飯也很好吃。",
      "pinyin": "Chúle niúròumiàn yǐwài, zhè jiā cāntīng de lǔròufàn yě hěn hǎochī.",
      "pinyin_numeric": "chu2le niu2rou4mian4 yi3wai4, zhe4 jia1 can1ting1 de lu3rou4fan4 ye3 hen3 hao3chi1.",
      "translation_en": "Besides beef noodles, the braised pork rice at this restaurant is also delicious.",
      "translation_ko": "소고기 국수 외에도 이 식당의 루로우판도 맛있습니다."
    },
    {
      "text": "除了禮拜六以外，我每天都要上班。",
      "pinyin": "Chúle lǐbàiliù yǐwài, wǒ měitiān dōu yào shàngbān.",
      "pinyin_numeric": "chu2le li3bai4liu4 yi3wai4, wo3 mei3tian1 dou1 yao4 shang4ban1.",
      "translation_en": "Besides Saturday, I have to work every day.",
      "translation_ko": "토요일 외에는 매일 출근해야 합니다."
    },
    {
      "text": "除了這本書以外，我還有三本小說。",
      "pinyin": "Chúle zhè běn shū yǐwài, wǒ hái yǒu sān běn xiǎoshuō.",
      "pinyin_numeric": "chu2le zhe4 ben3 shu1 yi3wai4, wo3 hai2 you3 san1 ben3 xiao3shuo1.",
      "translation_en": "Besides this book, I also have three novels.",
      "translation_ko": "이 책 외에도 저는 소설 세 권이 더 있습니다."
    },
    {
      "text": "除了喝咖啡以外，他也很喜歡喝茶。",
      "pinyin": "Chúle hē kāfēi yǐwài, tā yě hěn xǐhuān hē chá.",
      "pinyin_numeric": "chu2le he1 ka1fei1 yi3wai4, ta1 ye3 hen3 xi3huan1 he1 cha2.",
      "translation_en": "Besides drinking coffee, he also really likes drinking tea.",
      "translation_ko": "커피를 마시는 것 외에도 그는 차 마시는 것을 아주 좋아합니다."
    },
    {
      "text": "除了走路以外，我們也可以坐捷運去車站。",
      "pinyin": "Chúle zǒulù yǐwài, wǒmen yě kěyǐ zuò jiéyùn qù chēzhàn.",
      "pinyin_numeric": "chu2le zou3lu4 yi3wai4, wo3men ye3 ke3yi3 zuo4 jie2yun4 qu4 che1zhan4.",
      "translation_en": "Besides walking, we can also take the MRT to the station.",
      "translation_ko": "걷는 것 외에도 지하철을 타고 역에 갈 수 있습니다."
    },
    {
      "text": "除了工作以外，他沒有其他的興趣。",
      "pinyin": "Chúle gōngzuò yǐwài, tā méiyǒu qítā de xìngqù.",
      "pinyin_numeric": "chu2le gong1zuo4 yi3wai4, ta1 mei2you3 qi2ta1 de xing4qu4.",
      "translation_en": "Besides work, he has no other interests.",
      "translation_ko": "일 외에는 다른 취미가 없습니다."
    },
    {
      "text": "除了颱風天以外，這家店每天都營業。",
      "pinyin": "Chúle táifēng tiān yǐwài, zhè jiā diàn měitiān dōu yíngyè.",
      "pinyin_numeric": "chu2le tai2feng1 tian1 yi3wai4, zhe4 jia1 dian4 mei3tian1 dou1 ying2ye4.",
      "translation_en": "Besides typhoon days, this store is open every day.",
      "translation_ko": "태풍이 오는 날 외에는 이 가게는 매일 영업합니다."
    },
    {
      "text": "除了學中文以外，我還在學怎麼煮台灣小吃。",
      "pinyin": "Chúle xué zhōngwén yǐwài, wǒ hái zài xué zěnme zhǔ táiwān xiǎochī.",
      "pinyin_numeric": "chu2le xue2 zhong1wen2 yi3wai4, wo3 hai2 zai4 xue2 zen3me zhu3 tai2wan1 xiao3chi1.",
      "translation_en": "Besides learning Chinese, I am also learning how to cook Taiwanese snacks.",
      "translation_ko": "중국어를 배우는 것 외에도 저는 대만 간식을 요리하는 방법을 배우고 있습니다."
    }
  ]
}
